SELECT provider_name, contact_info
FROM service_providers
WHERE experience > 5;

SELECT SUM(count_of_appointments) AS total_appointments
FROM appointments
WHERE appointment_month = 'YYYY-MM';

SELECT icb_ons_code, appointment_month, SUM(count_of_appointments) AS total_appointments
FROM appointments
GROUP BY icb_ons_code, appointment_month;

SELECT icb_ons_code, COUNT(appointment_id) AS total_appointments
FROM appointments
GROUP BY icb_ons_code;

SELECT COUNT(*) 
FROM appointments 
WHERE provider_id = (SELECT provider_id FROM service_providers WHERE provider_name = 'your_specific_provider_name');

SELECT COUNT(appointment_id) AS appointment_count
FROM appointments
WHERE service_setting = 'Examination';

SELECT DISTINCT service_setting
FROM appointments
WHERE icb_ons_code = 'location_code_here';

SELECT provider_id, icb_ons_code, appointment_month, SUM(count_of_appointments) as total_appointments
FROM appointments
GROUP BY provider_id, icb_ons_code, appointment_month;

SELECT service_setting
FROM appointments
WHERE appointment_id = 'YOUR_APPOINTMENT_ID';

SELECT *
FROM patient_feedback
WHERE appointment_id = 'your_appointment_id';
